UPDATE pilgrims p SET passport_number=NULLIF(d.passport_number,''),birth_date=d.birth_date,passport_expiry=d.passport_expiry,passport_issue_date=d.passport_issue_date,gender=d.gender,permit_number=d.permit_number,english_name=NULLIF(d.english_name,''),program_id=d.program_id
FROM data d JOIN groups g ON g.group_number=d.group_number::int
WHERE p.full_name=d.full_name AND p.group_id=g.id;